import React, { useState } from "react";

function TrainForm({ onNewTrain = () => {} }) {
  const [number, setNumber] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!number.trim()) return alert("Введите номер поезда");

    try {
      const res = await fetch("http://localhost:5050/trains", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ number: number.trim() })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Ошибка создания поезда");
      onNewTrain(data);
      setNumber("");
    } catch (err) {
      alert(err.message);
    }
  };

  return (
    <div>
      <h3>Добавить поезд</h3>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={number}
          onChange={e => setNumber(e.target.value)}
          placeholder="Номер поезда"
          required
        />
        <button type="submit">Создать</button>
      </form>
    </div>
  );
}

export default TrainForm;
